+function formatStatusLabel(rawStatus?: string): string {
+  if (!rawStatus) {
+    return 'stopped';
+  }
+  const normalized = rawStatus.toLowerCase();
+  if (normalized === 'running') {
+    return 'running';
+  }
+  if (normalized === 'failed' || normalized === 'not_running') {
